{
    <div class="alert alert-success">
        <h4>Appointment Confirmed!</h4>
        <p>Your appointment has been booked successfully.</p>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmitAsync">
        <DataAnnotationsValidator />

        @* ── STEP 1 ── *@
        <fieldset class="mb-4">
            <legend>Patient Information</legend>

            <div class="mb-3">
                <label class="form-label" for="patientName">Patient Name</label>
                <InputText id="patientName" class="form-control" @bind-Value="model.PatientName" />
                <ValidationMessage For="() => model.PatientName" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="email">Email</label>
                <InputText id="email" class="form-control" @bind-Value="model.Email" />
                <ValidationMessage For="() => model.Email" />
                @if (serverErrors.ContainsKey("Email"))
                {
                    <div class="validation-message">@serverErrors["Email"]</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="phone">Phone</label>
                <InputText id="phone" class="form-control" @bind-Value="model.Phone" />
                <ValidationMessage For="() => model.Phone" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="insurance">Insurance Provider</label>
                <InputSelect id="insurance" class="form-select" @bind-Value="model.InsuranceProvider">
                    <option value="">-- Select --</option>
                    <option value="Aetna">Aetna</option>
                    <option value="BlueCross">BlueCross</option>
                    <option value="Cigna">Cigna</option>
                    <option value="UnitedHealth">UnitedHealth</option>
                    <option value="None">None</option>
                </InputSelect>
                <ValidationMessage For="() => model.InsuranceProvider" />
            </div>
        </fieldset>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2Async">
                Next
            </button>
        }

        @* ── STEP 2 ── *@
        @if (showStep2)
        {
            <fieldset class="mb-4">
                <legend>Appointment Details</legend>

                <div class="mb-3">
                    <label class="form-label" for="doctor">Preferred Doctor</label>
                    <InputSelect id="doctor" class="form-select" @bind-Value="model.PreferredDoctor">
                        <option value="">-- Select --</option>
                        @foreach (var doc in doctors)
                        {
                            <option value="@doc">@doc</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => model.PreferredDoctor" />
                    @if (serverErrors.ContainsKey("PreferredDoctor"))
                    {
                        <div class="validation-message">@serverErrors["PreferredDoctor"]</div>
                    }
                </div>

                <div class="mb-3">
                    <label class="form-label" for="date">Date</label>
                    <InputDate id="date" class="form-control" @bind-Value="model.AppointmentDate" />
                    <ValidationMessage For="() => model.AppointmentDate" />
                </div>

                <div class="mb-3">
                    <label class="form-label" for="timeslot">Time Slot</label>
                    @if (model.PreferredDoctor is not null && model.AppointmentDate is not null)
                    {
                        <button type="button" class="btn btn-sm btn-outline-secondary ms-2 mb-1"
                                @onclick="LoadTimeSlotsAsync">
                            Refresh Slots
                        </button>
                    }
                    <InputSelect id="timeslot" class="form-select" @bind-Value="model.TimeSlot">
                        <option value="">-- Select --</option>
                        @foreach (var slot in timeSlots)
                        {
                            <option value="@slot">@slot</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => model.TimeSlot" />
                    @if (serverErrors.ContainsKey("TimeSlot"))
                    {
                        <div class="validation-message">@serverErrors["TimeSlot"]</div>
                    }
                </div>

                <div class="mb-3">
                    <label class="form-label" for="reason">Reason for Visit</label>
                    <InputTextArea id="reason" class="form-control" rows="3" @bind-Value="model.ReasonForVisit" />
                    <ValidationMessage For="() => model.ReasonForVisit" />
                </div>

                <button type="button" class="btn btn-secondary me-2" @onclick="BackToStep1">
                    Back
                </button>
                <button type="button" class="btn btn-warning me-2" @onclick="CheckAvailabilityAsync"
                        disabled="@isChecking">
                    @(isChecking ? "Checking…" : "Check Availability")
                </button>
                <button type="submit" class="btn btn-success" disabled="@(!availabilityConfirmed)">
                    Book Appointment
                </button>
            </fieldset>
        }
    </EditForm>
}

@code {
    private AppointmentModel model = new();
    private EditContext? editContext;
    private ValidationMessageStore? messageStore;

    private bool showStep2;
    private bool isBooked;
    private bool isChecking;
    private bool availabilityConfirmed;

    private List<string> doctors = new();
    private List<string> timeSlots = new();
    private Dictionary<string, string> serverErrors = new();

    protected override async Task OnInitializedAsync()
    {
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private async Task ProceedToStep2Async()
    {
        // Manually validate step-1 fields
        editContext = new EditContext(model);
        var isValid = editContext.Validate();

        // Only need step-1 fields valid to proceed
        if (string.IsNullOrWhiteSpace(model.PatientName) ||
            string.IsNullOrWhiteSpace(model.Email) ||
            string.IsNullOrWhiteSpace(model.Phone) ||
            string.IsNullOrWhiteSpace(model.InsuranceProvider))
        {
            return;
        }

        // Basic email format check
        if (!new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(model.Email))
        {
            return;
        }

        showStep2 = true;
        serverErrors.Clear();
        availabilityConfirmed = false;
    }

    private void BackToStep1()
    {
        showStep2 = false;
        serverErrors.Clear();
        availabilityConfirmed = false;
    }

    private async Task LoadTimeSlotsAsync()
    {
        if (model.PreferredDoctor is not null && model.AppointmentDate is not null)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                model.PreferredDoctor, model.AppointmentDate.Value);
            model.TimeSlot = null;
            availabilityConfirmed = false;
            serverErrors.Clear();
        }
    }

    private async Task CheckAvailabilityAsync()
    {
        serverErrors.Clear();
        availabilityConfirmed = false;

        // Validate step-2 required fields locally first
        if (string.IsNullOrWhiteSpace(model.PreferredDoctor) ||
            model.AppointmentDate is null ||
            string.IsNullOrWhiteSpace(model.TimeSlot) ||
            string.IsNullOrWhiteSpace(model.ReasonForVisit))
        {
            // Trigger validation display
            editContext = new EditContext(model);
            editContext.Validate();
            return;
        }

        if (model.AppointmentDate <= DateOnly.FromDateTime(DateTime.Today))
        {
            editContext = new EditContext(model);
            editContext.Validate();
            return;
        }

        if (model.ReasonForVisit?.Length > 500)
        {
            editContext = new EditContext(model);
            editContext.Validate();
            return;
        }

        isChecking = true;

        var errors = await AppointmentService.ValidatePatientAsync(
            model.Email!,
            model.InsuranceProvider!,
            model.PreferredDoctor!,
            model.TimeSlot!);

        isChecking = false;

        if (errors.Count > 0)
        {
            serverErrors = errors;
        }
        else
        {
            availabilityConfirmed = true;
        }
    }

    private async Task HandleSubmitAsync()
    {
        if (!availabilityConfirmed)
            return;

        var success = await AppointmentService.BookAppointmentAsync();
        if (success)
        {
            isBooked = true;
        }
    }
}
"}

