                    @if (model.PreferredDoctor is not null && model.AppointmentDate is not null)
                    {
                        <button type="button" class="btn btn-sm btn-outline-secondary ms-2 mb-1"
                                @onclick="LoadTimeSlotsAsync">
                            Refresh Slots
                        </button>
                    }
                    <InputSelect id="timeslot" class="form-select" @bind-Value="model.TimeSlot">
                        <option value="">-- Select --</option>
                        @foreach (var slot in timeSlots)
                        {
                            <option value="@slot">@slot</option>
